// Extract company data from Ivy.AI webhook
const body = $input.first().json.body || $input.first().json;

const company = {
  id: body.company?.id || body.id,
  name: body.company?.name || body.name,
  industry: body.company?.industry || body.industry || 'No especificada',
  contactEmail: body.company?.contactEmail || body.contactEmail || '',
  contactPhone: body.company?.contactPhone || body.contactPhone || '',
  website: body.company?.website || body.website || '',
  status: body.company?.status || body.status || 'active',
  createdAt: body.company?.createdAt || body.createdAt || new Date().toISOString(),
  source: body.source || 'ivy-ai-app',
  createdBy: body.createdBy || 'system'
};

const appContext = body.appContext || {};

return [{
  json: {
    company,
    appContext,
    event: 'company_created',
    timestamp: new Date().toISOString()
  }
}];

// ROPA Onboarding Logic for new company
const { company, appContext } = $input.first().json;

const onboardingPlan = {
  companyName: company.name,
  companyId: company.id,
  steps: [
    {
      step: 1,
      action: 'analyze_company',
      description: `Analizar perfil de ${company.name} - Industria: ${company.industry}`,
      status: 'completed'
    },
    {
      step: 2,
      action: 'create_initial_campaign',
      description: `Crear campaña inicial de email marketing para ${company.name}`,
      status: 'pending'
    },
    {
      step: 3,
      action: 'generate_email_templates',
      description: `Generar plantillas de email personalizadas para ${company.name}`,
      status: 'pending'
    },
    {
      step: 4,
      action: 'setup_lead_tracking',
      description: `Configurar seguimiento de leads para ${company.name}`,
      status: 'pending'
    },
    {
      step: 5,
      action: 'create_drive_folder',
      description: `Crear carpeta en Google Drive para ${company.name}`,
      status: 'pending'
    }
  ],
  totalSteps: 5,
  completedSteps: 1,
  notification: {
    title: `🏢 Nueva empresa registrada: ${company.name}`,
    message: `Se ha creado la empresa ${company.name} (${company.industry}). ROPA ha iniciado el proceso de onboarding automático con ${5} pasos.`,
    priority: 'high'
  }
};

return [{ json: { ...onboardingPlan, company } }];
